//image.tmdb.org/t/p/w500/dQdpnDxi1IVTEhVxDG0BTUFxq3q.jpg","tmdb_url":"https://www.themoviedb.org/person/1745409"},{"name":"Phan Bân Long","name_vi":"Phan Bân Long","name_original":"Pan Binlong","tmdb_id":2086256,"profile":"https://image.tmdb.org/t/p/w500/tZqn7yTFQMiMa2VFRojb3NOf311.jpg","tmdb_url":"https://www.themoviedb.org/person/2086256"},{"name":"Rui Xiu","name_vi":null,"name_original":"Rui Xiu","tmdb_id":2221064,"profile":"https://image.tmdb.org/t/p/w500/izCeX7GGfWekNoBmzoOJyyw7rdu.jpg","tmdb_url":"https://www.themoviedb.org/person/2221064"},{"name":"Ai Liya","name_vi":null,"name_original":"Ai Liya","tmdb_id":1542333,"profile":"https://image.tmdb.org/t/p/w500/qehdgUXOT4HEN0mL56dp1Zyqtw1.jpg","tmdb_url":"https://www.themoviedb.org/person/1542333"},{"name":"Wang Naixun","name_vi":null,"name_original":"Wang Naixun","tmdb_id":3089931,"profile":"https://image.tmdb.org/t/p/w500/b39WLVk53c9PPUg3C3Zw0USKxrO.jpg","tmdb_url":"https://www.themoviedb.org/person/3089931"},{"name":"Chen Bing","name_vi":null,"name_original":"Chen Bing","tmdb_id":2514645,"profile":"https://image.tmdb.org/t/p/w500/x1NMNlvBeUdCz4hbhFV0cGQ68rU.jpg","tmdb_url":"https://www.themoviedb.org/person/2514645"}]},{"id":"124","title":"Phồn Hoa Lụi Tàn","origin_name":"A Fairyland Beyond the Ordinary World","slug":"phon-hoa-lui-tan","thumb":"https://img.ophim.live/uploads/movies/phon-hoa-lui-tan-thumb.jpg","poster":"https://img.ophim.live/uploads/movies/phon-hoa-lui-tan-poster.jpg","year":"2026","type":"series","genre":[{"name":"Bí ẩn","slug":"bi-an"}],"country":[{"name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn tất (34/34)","quality":"HD","modified":"2026-03-01T15:16:24.518Z","is_4k":false,"is_exclusive":false,"status":"","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[],"description":"<p>Để điều tra nguyên nhân cái chết của chị gái, Tô Vũ Niệm đã thâm nhập vào \"Phồn Hoa Thâm Xứ\" – chốn ăn chơi xa hoa trụy lạc, cô vô tình bị cuốn vào cuộc chiến quyền mưu đẫm máu giữa Nhiếp Phong và Đồ Gia Thịnh, đồng thời phát hiện ra chị gái mình bị diệt khẩu vì nắm giữ một bằng chứng chí mạng. Hiểm nguy dồn dập kéo đến: bạn thân phản bội, \"đào chính\" hãm hại, lại còn bị Nhiếp Phong đưa vào tầm ngắm. Giữa cô và Đồ Gia Thịnh tồn tại mối quan hệ vừa là địch vừa là bạn. Ẩn sâu dưới vẻ hào nhoáng của chốn phồn hoa ấy, tất cả chỉ là những lời dối trá nhuốm máu.</p>","tmdb_id":312533,"cast":["Kim Hãn","Li Jianuo","Châu Tuấn Vỹ","Lin Yiting","Xue Yubin"],"director":[],"keywords":[],"cast_meta":[{"name":"Kim Hãn","name_vi":"Kim Hãn","name_original":"Jin Han","tmdb_id":2123398,"profile":"https://image.tmdb.org/t/p/w500/lelUjhsbZve5AMe2RWD1L9RCkXs.jpg","tmdb_url":"https://www.themoviedb.org/person/2123398"},{"name":"Li Jianuo","name_vi":null,"name_original":"Li Jianuo","tmdb_id":5865900,"profile":"https://image.tmdb.org/t/p/w500/cQK1oyJ0GiupcJFIbBzkI9h0w2w.jpg","tmdb_url":"https://www.themoviedb.org/person/5865900"},{"name":"Châu Tuấn Vỹ","name_vi":"Châu Tuấn Vỹ","name_original":"Jacky Zhou","tmdb_id":3044436,"profile":"https://image.tmdb.org/t/p/w500/tBpjurRC7xiYwV3tMScLnE0NDiN.jpg","tmdb_url":"https://www.themoviedb.org/person/3044436"},{"name":"Lin Yiting","name_vi":null,"name_original":"Lin Yiting","tmdb_id":3128579,"profile":"https://image.tmdb.org/t/p/w500/oWIEC3kyNKSFfOkn67GMX8ruNcs.jpg","tmdb_url":"https://www.themoviedb.org/person/3128579"},{"name":"Xue Yubin","name_vi":null,"name_original":"Xue Yubin","tmdb_id":4102360,"profile":"https://image.tmdb.org/t/p/w500/3euqi0UU5Jv4KukpAatMthrVavR.jpg","tmdb_url":"https://www.themoviedb.org/person/4102360"}]},{"id":"125","title":"Bake Your Dream","origin_name":"Bake Your Dream","slug":"bake-your-dream","thumb":"https://img.ophim.live/uploads/movies/bake-your-dream-thumb.jpg","poster":"https://img.ophim.live/uploads/movies/bake-your-dream-poster.jpg","year":"2026","type":"series","genre":[{"name":"Tài Liệu","slug":"tai-lieu"},{"name":"Tình Cảm","slug":"tinh-cam"}],"country":[{"name":"Hàn Quốc","slug":"han-quoc"}],"lang_key":"Vietsub","episode_current":"Trailer","quality":"HD","modified":"2026-03-01T15:16:24.518Z","is_4k":false,"is_exclusive":false,"status":"","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[],"description":"<p>Dự án sinh tồn làm bánh toàn cầu, Bake Your Dream, quy tụ những bậc thầy làm bánh xuất sắc nhất thế giới. Từ các đầu bếp bánh ngọt hàng đầu Hàn Quốc và những nghệ nhân làm bánh nổi tiếng thế giới đến những viên ngọc quý ẩn mình với những công thức độc đáo, các thí sinh được trang bị những \"vũ khí bí mật\" và triết lý riêng biệt sẽ bước lên sân khấu để tranh giành danh hiệu cao nhất. Giữa những thử thách cam go, liệu các bậc thầy kỳ cựu sẽ tỏa sáng với kỹ thuật hoàn hảo của mình, hay những ý tưởng táo bạo, mới mẻ sẽ chiếm lấy spotlight? Với cá tính, triết lý và kỹ năng độc đáo trong tay, cuộc chiến bắt đầu ngay từ khoảnh khắc họ bước đến trước lò nướng. Hương vị, mùi thơm, sự tận tâm và sáng tạo sẽ cùng hội tụ trong đấu trường này, nơi những chiếc bánh ngọt quyến rũ nhất thế giới ra đời.</p>","tmdb_id":312915,"cast":["Lee Da-hee","Rho Hee-young","Mimi","Kwon Seong-joon"],"director":[],"keywords":[],"cast_meta":[{"name":"Lee Da-hee","name_vi":null,"name_original":"Lee Da-hee","tmdb_id":123807,"profile":"https://image.tmdb.org/t/p/w500/uaZ0kMQOEKxxtfH9IWecBZ8c4DI.jpg","tmdb_url":"https://www.themoviedb.org/person/123807"},{"name":"Rho Hee-young","name_vi":null,"name_original":"Rho Hee-young","tmdb_id":2430096,"profile":"https://image.tmdb.org/t/p/w500/ufEPCc06PUS0Nojy0QBh331h4BV.jpg","tmdb_url":"https://www.themoviedb.org/person/2430096"},{"name":"Mimi","name_vi":null,"name_original":"Mimi","tmdb_id":1966738,"profile":"https://image.tmdb.org/t/p/w500/cFF6eU40I3mRzJk3JWNtbJjAfuR.jpg","tmdb_url":"https://www.themoviedb.org/person/1966738"},{"name":"Kwon Seong-joon","name_vi":null,"name_original":"Kwon Seong-joon","tmdb_id":4988208,"profile":"https://image.tmdb.org/t/p/w500/taeVUDFYg5BYZiKR95pW1O8qzzf.jpg","tmdb_url":"https://www.themoviedb.org/person/4988208"}]},{"id":"126","title":"Gala Nông Thôn Của A Quý","origin_name":"Agui’s Village Gala","slug":"gala-nong-thon-cua-a-quy","thumb":"https://img.ophim.live/uploads/movies/gala-nong-thon-cua-a-quy-thumb.jpg","poster":"https://img.ophim.live/uploads/movies/gala-nong-thon-cua-a-quy-poster.jpg","year":"2026","type":"series","genre":[{"name":"Chính kịch","slug":"chinh-kich"}],"country":[{"name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn tất (10/10)","quality":"HD","modified":"2026-03-01T15:16:24.518Z","is_4k":false,"is_exclusive":false,"status":"","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[],"description":"<p>Khi một người dân làng chán nản, A Gui, quyết tâm thực hiện ước mơ sống đến trăm tuổi của Yunxiang A Niang, anh đã tổ chức một buổi dạ tiệc để gắn kết cộng đồng lại với nhau. Bất chấp sự chế giễu và những trở ngại, quyết tâm và sự chân thành của anh đã truyền cảm hứng cho dân làng, dẫn đến một lễ hội ấm áp, khơi dậy tinh thần gia đình, tình cảm và sự đổi mới ở vùng nông thôn Trung Quốc.</p>","tmdb_id":304645,"cast":["Ke Nan","Chen Mengxi","Song Jialing","Xia Xiaobo","Ji Hongxing","Gong Rui","Wang Xiaomeng"],"director":[],"keywords":[],"cast_meta":[{"name":"Ke Nan","name_vi":null,"name_original":"Ke Nan","tmdb_id":5790470,"profile":"https://image.tmdb.org/t/p/w500/nY5Ho35TSmYincZ1bQzDgNbN6NU.jpg","tmdb_url":"https://www.themoviedb.org/person/5790470"},{"name":"Chen Mengxi","name_vi":null,"name_original":"Chen Mengxi","tmdb_id":2027681,"profile":"https://image.tmdb.org/t/p/w500/6glNiaXRDZGxR1Mm8iI6iKPVBKK.jpg","tmdb_url":"https://www.themoviedb.org/person/2027681"},{"name":"Song Jialing","name_vi":null,"name_original":"Song Jialing","tmdb_id":4228129,"profile":"https://image.tmdb.org/t/p/w500/66zAVL6ii2F4JqYqllFyPJQXiT0.jpg","tmdb_url":"https://www.themoviedb.org/person/4228129"},{"name":"Xia Xiaobo","name_vi":null,"name_original":"Xia Xiaobo","tmdb_id":5790472,"p